content.content:
  1→import type {
  2→	ModelTokensTrendData,
  3→	OverviewKPIs,
  4→	UsageTrendData,
  5→} from "@rudel/api-routes";
  6→import { user } from "@rudel/sql-schema";
  7→import { eq } from "drizzle-orm";
  8→import {
  9→	buildAbsoluteDateFilter,
 10→	buildDateFilter,
 11→	escapeString,
 12→	queryClickhouse,
 13→} from "../clickhouse.js";
 14→import { db } from "../db.js";
 15→
 16→export interface Insight {
 17→	type: "trend" | "performer" | "alert" | "info";
 18→	severity: "positive" | "warning" | "negative" | "info";
 19→	message: string;
 20→	link: string;
 21→}
 22→
 23→/**
 24→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 25→ */
 26→export async function getOverviewKPIs(
 27→	orgId: string,
 28→	startDate: string,
 29→	endDate: string,
 30→): Promise<OverviewKPIs> {
 31→	const org = escapeString(orgId);
 32→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
 33→
 34→	const [mainResult, subagentsResult, skillsResult, slashResult, totalResult] =
 35→		await Promise.all([
 36→			queryClickhouse<{
 37→				distinct_users: number;
 38→				distinct_sessions: number;
 39→				distinct_projects: number;
 40→			}>(`
 41→        SELECT
 42→          uniq(user_id) as distinct_users,
 43→          count() as distinct_sessions,
 44→          uniq(if(git_remote != '', git_remote, if(package_name != '', package_name, project_path))) as distinct_projects
 45→        FROM rudel.session_analytics
 46→        WHERE ${dateFilter}
 47→          AND organization_id = '${org}'
 48→      `),
 49→			queryClickhouse<{ count: number }>(`
 50→        SELECT uniqExact(val) as count
 51→        FROM rudel.session_analytics
 52→        ARRAY JOIN subagent_types as val
 53→        WHERE ${dateFilter}
 54→          AND organization_id = '${org}'
 55→          AND val != ''
 56→      `),
 57→			queryClickhouse<{ count: number }>(`
 58→        SELECT uniqExact(val) as count
 59→        FROM rudel.session_analytics
 60→        ARRAY JOIN skills as val
 61→        WHERE ${dateFilter}
 62→          AND organization_id = '${org}'
 63→          AND val != ''
 64→      `),
 65→			queryClickhouse<{ count: number }>(`
 66→        SELECT uniqExact(val) as count
 67→        FROM rudel.session_analytics
 68→        ARRAY JOIN slash_commands as val
 69→        WHERE ${dateFilter}
 70→          AND organization_id = '${org}'
 71→          AND val != ''
 72→      `),
 73→			queryClickhouse<{ count: number }>(`
 74→        SELECT count() as count
 75→        FROM rudel.session_analytics
 76→        WHERE organization_id = '${org}'
 77→      `),
 78→		]);
 79→
 80→	const row = mainResult[0];
 81→	if (!row) {
 82→		return {
 83→			distinct_users: 0,
 84→			distinct_sessions: 0,
 85→			distinct_projects: 0,
 86→			distinct_subagents: 0,
 87→			distinct_skills: 0,
 88→			distinct_slash_commands: 0,
 89→			total_sessions: 0,
 90→		};
 91→	}
 92→	// ClickHouse returns UInt64 as strings when output_format_json_quote_64bit_integers is true (the default)
 93→	return {
 94→		distinct_users: Number(row.distinct_users),
 95→		distinct_sessions: Number(row.distinct_sessions),
 96→		distinct_projects: Number(row.distinct_projects),
 97→		distinct_subagents: Number(subagentsResult[0]?.count ?? 0),
 98→		distinct_skills: Number(skillsResult[0]?.count ?? 0),
 99→		distinct_slash_commands: Number(slashResult[0]?.count ?? 0),
100→		total_sessions: Number(totalResult[0]?.count ?? 0),
101→	};
102→}
