104→/**
105→ * Get token usage broken down by model and day
106→ */
107→export async function getModelTokensTrend(
108→	orgId: string,
109→	startDate: string,
110→	endDate: string,
111→): Promise<ModelTokensTrendData[]> {
112→	const org = escapeString(orgId);
113→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
114→
115→	const query = `
116→    SELECT
117→      toDate(session_date) as date,
118→      model_used as model,
119→      sum(total_tokens) as total_tokens,
120→      sum(input_tokens) as input_tokens,
121→      sum(output_tokens) as output_tokens
122→    FROM rudel.session_analytics
123→    WHERE ${dateFilter}
124→      AND organization_id = '${org}'
125→      AND model_used != ''
126→      AND model_used != 'unknown'
127→    GROUP BY date, model
128→    ORDER BY date ASC, total_tokens DESC
129→  `;
130→
131→	return queryClickhouse<ModelTokensTrendData>(query);
132→}
