134→/**
135→ * Get detailed usage trend data aggregated by day
136→ */
137→export async function getUsageTrendDetailed(
138→	orgId: string,
139→	startDate: string,
140→	endDate: string,
141→): Promise<UsageTrendData[]> {
142→	const org = escapeString(orgId);
143→	const dateFilter = buildAbsoluteDateFilter(startDate, endDate);
144→
145→	const query = `
146→    SELECT
147→      toDate(session_date) as date,
148→      count() as sessions,
149→      uniq(user_id) as active_users,
150→      round(sum(actual_duration_min) / 60, 2) as total_hours,
151→      sum(total_tokens) as total_tokens
152→    FROM rudel.session_analytics
153→    WHERE ${dateFilter}
154→      AND organization_id = '${org}'
155→    GROUP BY date
156→    ORDER BY date ASC
157→  `;
158→
159→	return queryClickhouse<UsageTrendData>(query);
160→}
