162→/**
163→ * Generate rule-based insights from current data
164→ */
165→export async function getOverviewInsights(
166→	orgId: string,
167→	startDate: string,
168→	endDate: string,
169→): Promise<Insight[]> {
170→	const org = escapeString(orgId);
171→	const insights: Insight[] = [];
172→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
173→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
174→	const prevStart = new Date(prevEnd.getTime() - periodMs);
175→	const prevStartStr = prevStart.toISOString().slice(0, 10);
176→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
177→
178→	interface PeriodStats {
179→		total_sessions: number;
180→		total_users: number;
181→		avg_duration_min: number;
182→	}
183→
184→	const [currentData, previousData, topPerformerData, silos] =
185→		await Promise.all([
186→			queryClickhouse<PeriodStats>(`
187→      SELECT
188→        count() as total_sessions,
189→        uniq(user_id) as total_users,
190→        round(avg(actual_duration_min), 2) as avg_duration_min
191→      FROM rudel.session_analytics
192→      WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
193→        AND organization_id = '${org}'
194→    `),
195→			queryClickhouse<PeriodStats>(`
196→      SELECT
197→        count() as total_sessions,
198→        uniq(user_id) as total_users,
199→        round(avg(actual_duration_min), 2) as avg_duration_min
200→      FROM rudel.session_analytics
201→      WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
202→        AND organization_id = '${org}'
203→    `),
204→			queryClickhouse<{
205→				user_id: string;
206→				sessions: number;
207→				total_hours: number;
208→			}>(`
209→      SELECT
210→        user_id,
211→        count() as sessions,
212→        round(sum(actual_duration_min) / 60, 1) as total_hours
213→      FROM rudel.session_analytics
214→      WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
215→        AND organization_id = '${org}'
216→      GROUP BY user_id
217→      ORDER BY sessions DESC
218→      LIMIT 1
219→    `),
220→			queryClickhouse<{
221→				project_path: string;
222→				unique_users: number;
223→				sessions: number;
224→			}>(`
225→      SELECT
226→        project_path,
227→        uniq(user_id) as unique_users,
228→        count() as sessions
229→      FROM rudel.session_analytics
230→      WHERE ${buildDateFilter(30)}
231→        AND organization_id = '${org}'
232→      GROUP BY project_path
233→      HAVING unique_users = 1 AND sessions >= 5
234→      ORDER BY sessions DESC
235→    `),
236→		]);
237→
238→	const current = currentData[0];
239→	const previous = previousData[0] || { total_sessions: 0 };
240→
241→	// Insight 1: Session trend analysis
242→	if (current && previous) {
243→		const sessionChange =
244→			previous.total_sessions > 0
245→				? ((current.total_sessions - previous.total_sessions) /
246→						previous.total_sessions) *
247→					100
248→				: 0;
249→
250→		if (Math.abs(sessionChange) >= 10) {
251→			const direction = sessionChange > 0 ? "up" : "down";
252→			const severity = sessionChange > 0 ? "positive" : "warning";
253→			insights.push({
254→				type: "trend",
255→				severity,
256→				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
257→				link: "/dashboard/team",
258→			});
259→		}
260→	}
261→
262→	// Insight 2: Top performer identification
263→	if (topPerformerData.length > 0 && topPerformerData[0]) {
264→		const performer = topPerformerData[0];
265→		const [userData] = await db
266→			.select({ name: user.name })
267→			.from(user)
268→			.where(eq(user.id, performer.user_id))
269→			.limit(1);
270→		const displayName =
271→			userData?.name || `${performer.user_id.substring(0, 8)}...`;
272→
273→		insights.push({
274→			type: "performer",
275→			severity: "info",
276→			message: `Top contributor: ${displayName} (${performer.sessions} sessions, ${performer.total_hours}h)`,
277→			link: `/dashboard/developers/${performer.user_id}`,
278→		});
279→	}
280→
281→	// Insight 3: Knowledge silos detection (uses a wider 30-day window)
282→	if (silos.length > 0) {
283→		insights.push({
284→			type: "alert",
285→			severity: "warning",
286→			message: `${silos.length} project${silos.length > 1 ? "s" : ""} with only one developer - risk of knowledge silos`,
287→			link: "/dashboard/projects",
288→		});
289→	}
290→
291→	return insights.slice(0, 3);
292→}
293→
294→export interface TeamSummaryPeriodData {
295→	total_sessions: number;
296→	active_users: number;
297→	avg_duration_min: number;
298→	avg_sessions_per_user: number;
299→}
300→
301→/**
302→ * Get team summary with previous period comparison
303→ */
304→export async function getTeamSummaryWithComparison(
305→	orgId: string,
306→	startDate: string,
307→	endDate: string,
308→) {
309→	const org = escapeString(orgId);
310→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
311→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
312→	const prevStart = new Date(prevEnd.getTime() - periodMs);
313→	const prevStartStr = prevStart.toISOString().slice(0, 10);
314→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
315→
316→	const currentQuery = `
317→    SELECT
318→      count() as total_sessions,
319→      uniq(user_id) as active_users,
320→      round(avg(actual_duration_min), 2) as avg_duration_min,
321→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
322→    FROM rudel.session_analytics
323→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
324→      AND organization_id = '${org}'
325→  `;
326→
327→	const previousQuery = `
328→    SELECT
329→      count() as total_sessions,
330→      uniq(user_id) as active_users,
331→      round(avg(actual_duration_min), 2) as avg_duration_min,
332→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
333→    FROM rudel.session_analytics
334→    WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
335→      AND organization_id = '${org}'
336→  `;
337→
338→	const [currentData, previousData] = await Promise.all([
339→		queryClickhouse<TeamSummaryPeriodData>(currentQuery),
340→		queryClickhouse<TeamSummaryPeriodData>(previousQuery),
341→	]);
342→
343→	const defaultPeriod: TeamSummaryPeriodData = {
344→		total_sessions: 0,
345→		active_users: 0,
346→		avg_duration_min: 0,
347→		avg_sessions_per_user: 0,
348→	};
349→
350→	const current = currentData[0] || defaultPeriod;
351→	const previous = previousData[0] || defaultPeriod;
352→
353→	const calculateChange = (curr: number, prev: number) => {
354→		if (!prev || prev === 0) return 0;
355→		return ((curr - prev) / prev) * 100;
356→	};
357→
358→	const changes = {
359→		total_sessions: calculateChange(
360→			current.total_sessions || 0,
361→			previous.total_sessions || 0,
362→		),
363→		active_users: calculateChange(
364→			current.active_users || 0,
365→			previous.active_users || 0,
366→		),
367→		avg_duration_min: calculateChange(
368→			current.avg_duration_min || 0,
369→			previous.avg_duration_min || 0,
370→		),
371→		avg_sessions_per_user: calculateChange(
372→			current.avg_sessions_per_user || 0,
373→			previous.avg_sessions_per_user || 0,
374→		),
375→	};
376→
377→	return { current, previous, changes };
378→}
