380→/**
381→ * Get session success rate metrics with comparison
382→ */
383→export async function getSuccessRateMetrics(
384→	orgId: string,
385→	startDate: string,
386→	endDate: string,
387→) {
388→	const org = escapeString(orgId);
389→	const periodMs = new Date(endDate).getTime() - new Date(startDate).getTime();
390→	const prevEnd = new Date(new Date(startDate).getTime() - 1);
391→	const prevStart = new Date(prevEnd.getTime() - periodMs);
392→	const prevStartStr = prevStart.toISOString().slice(0, 10);
393→	const prevEndStr = prevEnd.toISOString().slice(0, 10);
394→
395→	const currentQuery = `
396→    SELECT
397→      count() as total_sessions,
398→      round(avg(success_score), 1) as avg_success_score,
399→      countIf(success_score >= 70) as high_quality_sessions
400→    FROM rudel.session_analytics
401→    WHERE ${buildAbsoluteDateFilter(startDate, endDate)}
402→      AND organization_id = '${org}'
403→  `;
404→
405→	const previousQuery = `
406→    SELECT
407→      count() as total_sessions,
408→      round(avg(success_score), 1) as avg_success_score,
409→      countIf(success_score >= 70) as high_quality_sessions
410→    FROM rudel.session_analytics
411→    WHERE ${buildAbsoluteDateFilter(prevStartStr, prevEndStr)}
412→      AND organization_id = '${org}'
413→  `;
414→
415→	interface SuccessRateStats {
416→		total_sessions: number;
417→		avg_success_score: number;
418→		high_quality_sessions: number;
419→	}
420→
421→	const [currentData, previousData] = await Promise.all([
422→		queryClickhouse<SuccessRateStats>(currentQuery),
423→		queryClickhouse<SuccessRateStats>(previousQuery),
424→	]);
425→
426→	const current: SuccessRateStats = currentData[0] || {
427→		total_sessions: 0,
428→		avg_success_score: 0,
429→		high_quality_sessions: 0,
430→	};
431→
432→	const previous: SuccessRateStats = previousData[0] || {
433→		total_sessions: 0,
434→		avg_success_score: 0,
435→		high_quality_sessions: 0,
436→	};
437→
438→	const currentSuccessRate =
439→		current.total_sessions > 0
440→			? (current.high_quality_sessions / current.total_sessions) * 100
441→			: 0;
442→
443→	const previousSuccessRate =
444→		previous.total_sessions > 0
445→			? (previous.high_quality_sessions / previous.total_sessions) * 100
446→			: 0;
447→
448→	return {
449→		current: {
450→			high_quality_sessions: current.high_quality_sessions,
451→			total_sessions: current.total_sessions,
452→			success_rate: currentSuccessRate,
453→		},
